/*Edit this prefix to the prefix used by your own design system */
const PREFIX = "vf-";

(function(){const prefix=PREFIX;if(prefix===null||prefix===''){return;}const elementsWithPrefix=document.querySelectorAll('*[class*=\''+prefix+'\']');const allElements=document.querySelectorAll('*');elementsWithPrefix.forEach(el=>{el.style.outline='2px solid green';el.style.position='relative';});allElements.forEach(el=>{if(![...el.classList].some(cls=>cls.startsWith(prefix))){el.style.outline='4px solid red';el.style.position='relative';}});})();
